window.Swal = window.Swal || {
  fire: function (options) {
    options = options || {};
    var message = options.text || options.title || '';
    var result = options.showCancelButton ? window.confirm(message) : (window.alert(message), true);
    return Promise.resolve({ isConfirmed: result, isDismissed: !result });
  }
};
